// frontend/src/components/ProtectedRoute.jsx
import { Navigate } from 'react-router-dom';
import { useEffect, useState } from 'react';

export default function ProtectedRoute({ children, adminOnly = false }) {
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    // Check localStorage directly - NO API CALL
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('role');
    
    console.log('🔍 ProtectedRoute - Token:', token ? 'exists' : 'none');
    console.log('🔍 ProtectedRoute - Role:', role);
    
    if (!token) {
      setIsAuthenticated(false);
      setLoading(false);
      return;
    }

    // Just check localStorage - don't call the API
    setIsAuthenticated(true);
    setIsAdmin(role === 'admin');
    
    console.log('🔍 ProtectedRoute - IsAdmin:', role === 'admin');
    setLoading(false);
  }, []);

  if (loading) {
    return <div style={{ padding: '20px', textAlign: 'center' }}>Loading...</div>;
  }

  if (!isAuthenticated) {
    console.log('🔍 ProtectedRoute - Not authenticated, redirecting to /auth');
    return <Navigate to="/auth" replace />;
  }

  if (adminOnly && !isAdmin) {
    console.log('🔍 ProtectedRoute - Not admin, redirecting to /dashboard');
    return <Navigate to="/dashboard" replace />;
  }

  console.log('🔍 ProtectedRoute - Rendering children');
  return children;
}
